<?php
namespace Tests\Feature;
use App\Domain\Shops\ShopSaleSourceType;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use App\Models\Shop;use App\Models\ShopSale;use App\Models\User;use Illuminate\Database\QueryException;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
final class ShopSaleSchemaTest extends TestCase{use RefreshDatabase;public function test_sale_configuration_and_ledger_schema_are_safe(){$this->assertTrue(Schema::hasColumns('items',['is_sellable','sell_price']));$this->assertTrue(Schema::hasColumns('shops',['buys_items','purchase_rate_basis_points']));$this->assertTrue(Schema::hasColumns('shop_sales',['shop_id','character_id','item_id','item_instance_id','character_item_id_snapshot','source_type','quantity_sold','unit_gold','total_gold','idempotency_key','sold_at','metadata']));$meta=DB::selectOne('SELECT ENGINE,TABLE_COLLATION FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=?',['shop_sales']);$this->assertSame('InnoDB',$meta->ENGINE);$this->assertSame('utf8mb4_unicode_ci',$meta->TABLE_COLLATION);$column=DB::selectOne('SELECT COLLATION_NAME FROM information_schema.COLUMNS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=? AND COLUMN_NAME=?',['shop_sales','idempotency_key']);$this->assertSame('ascii_bin',$column->COLLATION_NAME);$this->assertFalse(Schema::hasColumn('shop_sales','status'));}public function test_sale_relations_and_restrictive_history_are_preserved(){$shop=Shop::factory()->create();$character=Character::factory()->for(User::factory())->create();$item=$this->item();$instance=ItemInstance::create(['uuid'=>'11111111-1111-5111-8111-111111111111','character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>0,'status'=>'available','origin_type'=>'test','origin_id'=>1,'origin_unit_index'=>1,'acquired_at'=>now()]);$sale=ShopSale::create(['shop_id'=>$shop->id,'character_id'=>$character->id,'item_id'=>$item->id,'item_instance_id'=>$instance->id,'source_type'=>ShopSaleSourceType::INSTANCE,'quantity_sold'=>1,'unit_gold'=>25,'total_gold'=>25,'idempotency_key'=>'22222222-2222-5222-8222-222222222222','sold_at'=>now(),'metadata'=>['version'=>1]]);$this->assertTrue($sale->shop->is($shop));$this->assertTrue($sale->character->is($character));$this->assertTrue($sale->item->is($item));$this->assertTrue($sale->itemInstance->is($instance));foreach([$shop,$character,$item,$instance]as$model){try{$model->delete();$this->fail('Historical sale dependency was deleted.');}catch(QueryException $e){$this->assertSame('23000',(string)$e->getCode());}}}private function item(){return Item::create(['code'=>'sale-schema-item','name'=>'Sale Item','item_type'=>'equipment','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'is_sellable'=>true,'sell_price'=>25,'status'=>'active']);}}
